// A call to `Intercept(f, g, h)` equals to `reviewpolicy.Intercept(f(g(h())))`.
func (c *ReviewPolicyClient) Intercept(interceptors ...Interceptor) {
	c.inters.ReviewPolicy = append(c.inters.ReviewPolicy, interceptors...)
}

